class SQLQueryValidator {
  private val forbiddenKeywords = Set(
    "DROP", "DELETE", "TRUNCATE", "ALTER", "CREATE", "INSERT", 
    "UPDATE", "GRANT", "REVOKE", "EXEC", "EXECUTE"
  )
  
  private val dangerousPatterns = Seq(
    """--""",
    """/\*""",
    """\*/""",
    """;\s*DROP""",
    """;\s*DELETE""",
    """;\s*INSERT""",
    """;\s*UPDATE"""
  )
  
  def validate(query: String): Either[String, String] = {
    val upperQuery = query.toUpperCase.trim
    
    if (query.trim.isEmpty) {
      return Left("Query cannot be empty")
    }
    
    forbiddenKeywords.foreach { keyword =>
      if (upperQuery.contains(keyword)) {
        return Left(s"Forbidden keyword detected: $keyword")
      }
    }
    
    dangerousPatterns.foreach { pattern =>
      if (upperQuery.matches(s".*$pattern.*")) {
        return Left(s"Dangerous pattern detected: $pattern")
      }
    }
    
    if (!upperQuery.startsWith("SELECT") && 
        !upperQuery.startsWith("WITH") && 
        !upperQuery.startsWith("SHOW") &&
        !upperQuery.startsWith("DESCRIBE") &&
        !upperQuery.startsWith("EXPLAIN")) {
      return Left("Only SELECT, WITH, SHOW, DESCRIBE, and EXPLAIN queries are allowed")
    }
    
    val semicolonCount = query.count(_ == ';')
    if (semicolonCount > 1 || (semicolonCount == 1 && !query.trim.endsWith(";"))) {
      return Left("Multiple statements or SQL injection attempt detected")
    }
    
    Right(query.trim.stripSuffix(";"))
  }
}

class QueryExecutor(spark: SparkSession) {
  private val validator = new SQLQueryValidator()
  private val queryCache = new ConcurrentHashMap[String, QueryResult]()
  
  def executeQuery(request: QueryRequest): QueryResult = {
    val startTime = System.currentTimeMillis()
    
    validator.validate(request.sqlQuery) match {
      case Left(error) =>
        QueryResult(
          queryId = request.queryId,
          success = false,
          executionTimeMs = System.currentTimeMillis() - startTime,
          error = Some(s"Validation failed: $error")
        )
      
      case Right(validatedQuery) =>
        Try {
          val maxRows = request.maxRows.getOrElse(1000)
          val timeoutSeconds = request.timeoutSeconds.getOrElse(300)
          
          spark.conf.set("spark.sql.execution.timeout", s"${timeoutSeconds}s")
          
          val df = spark.sql(validatedQuery)
          
          val limitedDf = df.limit(maxRows)
          val rows = limitedDf.collect()
          
          val data = rows.map { row =>
            row.schema.fields.zipWithIndex.map { case (field, idx) =>
              field.name -> (if (row.isNullAt(idx)) null else row.get(idx))
            }.toMap
          }
          
          QueryResult(
            queryId = request.queryId,
            success = true,
            data = Some(data),
            schema = Some(df.schema),
            rowCount = Some(rows.length),
            executionTimeMs = System.currentTimeMillis() - startTime
          )
        } match {
          case Success(result) => result
          case Failure(exception) =>
            QueryResult(
              queryId = request.queryId,
              success = false,
              executionTimeMs = System.currentTimeMillis() - startTime,
              error = Some(s"Execution failed: ${exception.getMessage}")
            )
        }
    }
  }
  
  def executeQueryWithCache(request: QueryRequest, cacheDuration: Duration = 5.minutes): QueryResult = {
    val cacheKey = s"${request.userId}_${request.sqlQuery}"
    
    Option(queryCache.get(cacheKey)) match {
      case Some(cachedResult) if isCacheValid(cachedResult, cacheDuration) =>
        cachedResult
      case _ =>
        val result = executeQuery(request)
        if (result.success) {
          queryCache.put(cacheKey, result)
        }
        result
    }
  }
  
  private def isCacheValid(result: QueryResult, duration: Duration): Boolean = {
    val now = System.currentTimeMillis()
    now - result.executionTimeMs < duration.toMillis
  }
  
  def clearCache(): Unit = {
    queryCache.clear()
  }
}

