class QueryAuditLogger {
  case class AuditLog(
    queryId: String,
    userId: String,
    query: String,
    timestamp: Long,
    success: Boolean,
    executionTimeMs: Long,
    error: Option[String]
  )
  
  private val logs = scala.collection.mutable.ListBuffer[AuditLog]()
  
  def log(request: QueryRequest, result: QueryResult): Unit = {
    val auditLog = AuditLog(
      queryId = request.queryId,
      userId = request.userId,
      query = request.sqlQuery,
      timestamp = System.currentTimeMillis(),
      success = result.success,
      executionTimeMs = result.executionTimeMs,
      error = result.error
    )
    logs.synchronized {
      logs += auditLog
    }
  }
  
  def getLogs(userId: Option[String] = None, limit: Int = 100): Seq[AuditLog] = {
    logs.synchronized {
      val filtered = userId match {
        case Some(uid) => logs.filter(_.userId == uid)
        case None => logs
      }
      filtered.takeRight(limit).toSeq
    }
  }
  
  def clearLogs(): Unit = {
    logs.synchronized {
      logs.clear()
    }
  }
}

class BigDataAnalyticsPlatform(spark: SparkSession, dataLakePath: String) {
  private val queryExecutor = new QueryExecutor(spark)
  private val dataLakeRegistry = new DataLakeRegistry(spark)
  private val auditLogger = new QueryAuditLogger()
  
  def initialize(): Unit = {
    dataLakeRegistry.registerTables(dataLakePath)
    println(s"Registered tables: ${dataLakeRegistry.listAvailableTables().mkString(", ")}")
  }
  
  def processAPIRequest(request: QueryRequest): QueryResult = {
    val result = queryExecutor.executeQuery(request)
    auditLogger.log(request, result)
    result
  }
  
  def processAPIRequestWithCache(request: QueryRequest): QueryResult = {
    val result = queryExecutor.executeQueryWithCache(request)
    auditLogger.log(request, result)
    result
  }
  
  def getAvailableTables(): Seq[String] = {
    dataLakeRegistry.listAvailableTables()
  }
  
  def getAuditLogs(userId: Option[String] = None, limit: Int = 100): Seq[QueryAuditLogger#AuditLog] = {
    auditLogger.getLogs(userId, limit)
  }
  
  def clearCache(): Unit = {
    queryExecutor.clearCache()
  }
}

